9400 /// Return true if "icmp LPred X, LCR" implies "icmp RPred X, RCR" is true.
9401 /// Return false if "icmp LPred X, LCR" implies "icmp RPred X, RCR" is false.
9402 /// Otherwise, return std::nullopt if we can't infer anything.
9403 static std::optional<bool>
9404 isImpliedCondCommonOperandWithCR(CmpPredicate LPred, const ConstantRange &LCR,
9405                                  CmpPredicate RPred, const ConstantRange &RCR) {
9406   auto CRImpliesPred = [&](ConstantRange CR,
9407                            CmpInst::Predicate Pred) -> std::optional<bool> {
9408     // If all true values for lhs and true for rhs, lhs implies rhs
9409     if (CR.icmp(Pred, RCR))
9410       return true;
9411 
9412     // If there is no overlap, lhs implies not rhs
9413     if (CR.icmp(CmpInst::getInversePredicate(Pred), RCR))
9414       return false;
9415 
9416     return std::nullopt;
9417   };
9418   if (auto Res = CRImpliesPred(ConstantRange::makeAllowedICmpRegion(LPred, LCR),
9419                                RPred))
9420     return Res;
9421   if (LPred.hasSameSign() ^ RPred.hasSameSign()) {
9422     LPred = LPred.hasSameSign() ? ICmpInst::getFlippedSignednessPredicate(LPred)
9423                                 : static_cast<CmpInst::Predicate>(LPred);
9424     RPred = RPred.hasSameSign() ? ICmpInst::getFlippedSignednessPredicate(RPred)
9425                                 : static_cast<CmpInst::Predicate>(RPred);
9426     return CRImpliesPred(ConstantRange::makeAllowedICmpRegion(LPred, LCR),
9427                          RPred);
9428   }
9429   return std::nullopt;
9430 }
