9529 /// Return true if LHS implies RHS is true.  Return false if LHS implies RHS is
9530 /// false.  Otherwise, return std::nullopt if we can't infer anything.  We
9531 /// expect the RHS to be an icmp and the LHS to be an 'and', 'or', or a 'select'
9532 /// instruction.
9533 static std::optional<bool>
9534 isImpliedCondAndOr(const Instruction *LHS, CmpPredicate RHSPred,
9535                    const Value *RHSOp0, const Value *RHSOp1,
9536                    const DataLayout &DL, bool LHSIsTrue, unsigned Depth) {
9537   // The LHS must be an 'or', 'and', or a 'select' instruction.
9538   assert((LHS->getOpcode() == Instruction::And ||
9539           LHS->getOpcode() == Instruction::Or ||
9540           LHS->getOpcode() == Instruction::Select) &&
9541          "Expected LHS to be 'and', 'or', or 'select'.");
9542 
9543   assert(Depth <= MaxAnalysisRecursionDepth && "Hit recursion limit");
9544 
9545   // If the result of an 'or' is false, then we know both legs of the 'or' are
9546   // false.  Similarly, if the result of an 'and' is true, then we know both
9547   // legs of the 'and' are true.
9548   const Value *ALHS, *ARHS;
9549   if ((!LHSIsTrue && match(LHS, m_LogicalOr(m_Value(ALHS), m_Value(ARHS)))) ||
9550       (LHSIsTrue && match(LHS, m_LogicalAnd(m_Value(ALHS), m_Value(ARHS))))) {
9551     // FIXME: Make this non-recursion.
9552     if (std::optional<bool> Implication = isImpliedCondition(
9553             ALHS, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue, Depth + 1))
9554       return Implication;
9555     if (std::optional<bool> Implication = isImpliedCondition(
9556             ARHS, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue, Depth + 1))
9557       return Implication;
9558     return std::nullopt;
9559   }
9560   return std::nullopt;
9561 }
9562 
9563 std::optional<bool>
9564 llvm::isImpliedCondition(const Value *LHS, CmpPredicate RHSPred,
9565                          const Value *RHSOp0, const Value *RHSOp1,
9566                          const DataLayout &DL, bool LHSIsTrue, unsigned Depth) {
9567   // Bail out when we hit the limit.
9568   if (Depth == MaxAnalysisRecursionDepth)
9569     return std::nullopt;
9570 
9571   // A mismatch occurs when we compare a scalar cmp to a vector cmp, for
9572   // example.
9573   if (RHSOp0->getType()->isVectorTy() != LHS->getType()->isVectorTy())
9574     return std::nullopt;
9575 
9576   assert(LHS->getType()->isIntOrIntVectorTy(1) &&
9577          "Expected integer type only!");
9578 
9579   // Match not
9580   if (match(LHS, m_Not(m_Value(LHS))))
9581     LHSIsTrue = !LHSIsTrue;
9582 
9583   // Both LHS and RHS are icmps.
9584   const ICmpInst *LHSCmp = dyn_cast<ICmpInst>(LHS);
9585   if (LHSCmp)
9586     return isImpliedCondICmps(LHSCmp, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue);
9587 
9588   /// The LHS should be an 'or', 'and', or a 'select' instruction.  We expect
9589   /// the RHS to be an icmp.
9590   /// FIXME: Add support for and/or/select on the RHS.
9591   if (const Instruction *LHSI = dyn_cast<Instruction>(LHS)) {
9592     if ((LHSI->getOpcode() == Instruction::And ||
9593          LHSI->getOpcode() == Instruction::Or ||
9594          LHSI->getOpcode() == Instruction::Select))
9595       return isImpliedCondAndOr(LHSI, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue,
9596                                 Depth);
9597   }
9598   return std::nullopt;
9599 }
9600 
9601 std::optional<bool> llvm::isImpliedCondition(const Value *LHS, const Value *RHS,
9602                                              const DataLayout &DL,
9603                                              bool LHSIsTrue, unsigned Depth) {
9604   // LHS ==> RHS by definition
9605   if (LHS == RHS)
9606     return LHSIsTrue;
9607 
9608   // Match not
9609   bool InvertRHS = false;
9610   if (match(RHS, m_Not(m_Value(RHS)))) {
9611     if (LHS == RHS)
9612       return !LHSIsTrue;
9613     InvertRHS = true;
9614   }
9615 
9616   if (const ICmpInst *RHSCmp = dyn_cast<ICmpInst>(RHS)) {
9617     if (auto Implied = isImpliedCondition(
9618             LHS, RHSCmp->getCmpPredicate(), RHSCmp->getOperand(0),
9619             RHSCmp->getOperand(1), DL, LHSIsTrue, Depth))
9620       return InvertRHS ? !*Implied : *Implied;
9621     return std::nullopt;
9622   }
9623 
9624   if (Depth == MaxAnalysisRecursionDepth)
9625     return std::nullopt;
9626 
9627   // LHS ==> (RHS1 || RHS2) if LHS ==> RHS1 or LHS ==> RHS2
9628   // LHS ==> !(RHS1 && RHS2) if LHS ==> !RHS1 or LHS ==> !RHS2
9629   const Value *RHS1, *RHS2;
9630   if (match(RHS, m_LogicalOr(m_Value(RHS1), m_Value(RHS2)))) {
9631     if (std::optional<bool> Imp =
9632             isImpliedCondition(LHS, RHS1, DL, LHSIsTrue, Depth + 1))
9633       if (*Imp == true)
9634         return !InvertRHS;
9635     if (std::optional<bool> Imp =
9636             isImpliedCondition(LHS, RHS2, DL, LHSIsTrue, Depth + 1))
9637       if (*Imp == true)
9638         return !InvertRHS;
9639   }
9640   if (match(RHS, m_LogicalAnd(m_Value(RHS1), m_Value(RHS2)))) {
9641     if (std::optional<bool> Imp =
9642             isImpliedCondition(LHS, RHS1, DL, LHSIsTrue, Depth + 1))
9643       if (*Imp == false)
9644         return InvertRHS;
9645     if (std::optional<bool> Imp =
9646             isImpliedCondition(LHS, RHS2, DL, LHSIsTrue, Depth + 1))
9647       if (*Imp == false)
9648         return InvertRHS;
9649   }
9650 
9651   return std::nullopt;
9652 }
9653 
9654 // Returns a pair (Condition, ConditionIsTrue), where Condition is a branch
9655 // condition dominating ContextI or nullptr, if no condition is found.
9656 static std::pair<Value *, bool>
9657 getDomPredecessorCondition(const Instruction *ContextI) {
9658   if (!ContextI || !ContextI->getParent())
9659     return {nullptr, false};
9660 
9661   // TODO: This is a poor/cheap way to determine dominance. Should we use a
9662   // dominator tree (eg, from a SimplifyQuery) instead?
9663   const BasicBlock *ContextBB = ContextI->getParent();
9664   const BasicBlock *PredBB = ContextBB->getSinglePredecessor();
9665   if (!PredBB)
9666     return {nullptr, false};
9667 
9668   // We need a conditional branch in the predecessor.
9669   Value *PredCond;
9670   BasicBlock *TrueBB, *FalseBB;
9671   if (!match(PredBB->getTerminator(), m_Br(m_Value(PredCond), TrueBB, FalseBB)))
9672     return {nullptr, false};
9673 
9674   // The branch should get simplified. Don't bother simplifying this condition.
9675   if (TrueBB == FalseBB)
9676     return {nullptr, false};
9677 
9678   assert((TrueBB == ContextBB || FalseBB == ContextBB) &&
9679          "Predecessor block does not point to successor?");
